import type { ResponsesFolderData } from "@/api";
import { cn } from "@/utils/cn";
import { createEffect, type ComponentProps } from "solid-js";

interface FolderComponentProps extends ComponentProps<'div'> {
	folder: ResponsesFolderData;
	selectedFolder: () => string;
	setSelectedFolder: (id: string) => void;
	deleteFolder: (id: string) => void;
	indent?: number;
}

export default function FolderComponent(props: FolderComponentProps) {
	const { folder, selectedFolder, setSelectedFolder, deleteFolder, indent } = props;

	createEffect(() => {
		console.log(folder)
	})

	return <><div
		class={cn(`flex items-center py-1 px-2 cursor-pointer bg-primary text-primary-foreground hover:bg-primary/80 rounded-lg
		shadow-md hover:shadow-lg transition-all duration-200 shadow-slate-900/80 ease-in-out`, folder.id === selectedFolder() && 'bg-primary/80', indent && `ml-${indent}`)}
		onClick={() => setSelectedFolder(folder.id || '')}
	>
		<span class="mr-2 text-sm">📁</span>
		<span class="mr-2 text-sm">{folder.name}</span>
		<button
			onClick={(e) => {
				e.stopPropagation();
				deleteFolder(folder.id || '');
			}}
			class="ml-2 text-red-500 hover:text-red-700 text-xs px-1"
			title="Delete folder"
		>
			🗑
		</button>
	</div>
	{folder.children && folder.children.length > 0 && (
		<div>
			{folder.children.map((child) => (
				<FolderComponent
					folder={child}
					selectedFolder={selectedFolder}
					setSelectedFolder={setSelectedFolder}
					deleteFolder={deleteFolder}
				/>
			))}
		</div>

	)}
	</>
}
